local LSdkGtTrack = LxClass("LSdkGtTrack", nil)

local LxBehaviour = LxRequire("LApp.component.LxBehaviour")

function LSdkGtTrack:LSdkGtTrack()
    ---@type LxBehaviour
    self._behaviour = LxBehaviour:New()
end

function LSdkGtTrack:Dispose()
    if self._behaviour then
        self._behaviour:Dispose()
        self._behaviour = nil
    end
    table.removeall(self)
    self._isDispose = true
end

function LSdkGtTrack:Initialize()
    ---广告埋点
    self:RegTrackEvent()
end
