function LSdkGtTrack:RegTrackEvent()
    local eventReg = self._behaviour
    eventReg:AddEventHandler(EventNames.QUERY_REMOTE_FIlE_RESULT, function(isOk)
        if isOk then
            local afName = LSdkGtTrack.AF_CREATE_ROLE
            if not self:IsTrackRecorded(afName) then
                self:RecordedTrack(afName)
                self:SendTrackEvent(afName)
            end
        end
    end)

    eventReg:AddEventHandler(EventNames.ON_MAIN_BATTLE_FINISHED, function(battleNode)
        if battleNode == 20010 then
            local afName = LSdkGtTrack.AF_TUTORIAL_COMPLETION
            if not self:IsTrackRecorded(afName) then
                self:RecordedTrack(afName)
                self:SendTrackEvent(afName)
            end
        elseif battleNode == 20020 then
            --展示安装到桌面引导
            gLSdkImpl:CallMethod(LSdkMethod.ShowAddHomePopup)
        elseif battleNode == 20030 then
            --展示绑定弹窗引导
            gLSdkImpl:CallMethod(LSdkMethod.ShowBindPopup)
        end
    end)

    eventReg:AddEventHandler(EventNames.ON_PLAYER_LEVEL_CHANGE, function(_, newLevel)
        local afName = levelTb[newLevel]
        if afName then
            if not self:IsTrackRecorded(afName) then
                self:RecordedTrack(afName)
                self:SendTrackEvent(afName)
            end
        end
    end)

    eventReg:AddEventHandler(EventNames.ON_CHARGE_MONEY_CHANGE, function(oldMoney, newMoney)
        oldMoney = oldMoney or 0
        newMoney = newMoney or 0
        if not self._lastMoney then
            self._lastMoney = oldMoney
        end
        oldMoney = self._lastMoney
        self._lastMoney = newMoney
        for _, v in ipairs(moneyTb) do
            local money = v.money
            if oldMoney < money and newMoney >= money then
                if not self:IsTrackRecorded(v.afName) then
                    self:RecordedTrack(v.afName)
                    self:SendTrackEvent(v.afName)
                end
            end
        end
    end)

    eventReg:AddEventHandler(EventNames.PRIVILEGE_BUY_IDS, function(buyIds)
        if buyIds[2] or buyIds[4] or buyIds[6] or buyIds[7] then
            self:SendTrackEvent(LSdkGtTrack.AF_CARD_30D)
        end
    end)
end

function LSdkGtTrack:OnPlayerLogin()
    local dayPast = gModelPlayer:GetCreateDay()
    local afName
    if dayPast == 2 then
        afName = LSdkGtTrack.AF_RETENTION_2
    elseif dayPast >= 3 and dayPast < 7 then
        afName = LSdkGtTrack.AF_RETENTION_3
    elseif dayPast >= 7 then
        afName = LSdkGtTrack.AF_RETENTION_7
    end
    if afName and not self:IsTrackRecorded(afName) then
        self:RecordedTrack(afName)
        self:SendTrackEvent(afName)
    end
end

function LSdkGtTrack:SendTrackEvent(eventName, ...)
    if LOG_INFO_ENABLED then
        printInfoN("trackEvent", eventName, ...)
    end
    gLSdkImpl:CallMethod(LSdkMethod.TrackEvent, eventName, ...)
end

function LSdkGtTrack:IsTrackRecorded(afName)
    local ids = gModelPlayer and gModelPlayer:GetFireOneTimeEventIds() or {}
    local id = LSdkGtTrack.AF_IDS[afName]
    if not id then return true end
    
    if ids[id] then
        return true
    else
        return false
    end
end

function LSdkGtTrack:RecordedTrack(afName)
    if not gModelPlayer then return end

    local id = LSdkGtTrack.AF_IDS[afName]
    if not id then return end
    
    gModelPlayer:OnFireOnetimeEventReq(id)
end

return LSdkGtTrack